    12	/**
    13	 * 清理过期墓碑
    14	 * @param maxAgeDays  超过此天数的墓碑被永久移除，默认 7 天
    15	 */
    16	export function cleanupTombstones<T extends { _deleted?: boolean; updatedAt?: string }>(
    17	    items: T[],
    18	    maxAgeDays: number = 7,
    19	): T[] {
    20	    const cutoff = Date.now() - maxAgeDays * 24 * 60 * 60 * 1000;
    21	    return items.filter((item) => {
    22	        if (!item._deleted) return true;
    23	        if (!item.updatedAt) return true; // 无时间戳的墓碑保守保留
    24	        return new Date(item.updatedAt).getTime() > cutoff;
    25	    });
    26	}
    27	
    28	/**
    29	 * 比较两条同 ID 记录，返回较新的一条。
    30	 * - 都有 updatedAt → 取较晚的
    31	 * - 仅一条有 updatedAt → 取有的一条（由新代码写入）
    32	 * - 都没有 updatedAt → 保持原顺序（取 client）
    33	 */
    34	function pickNewer<T extends WithUpdatedAt>(a: T, b: T): T {
    35	    if (!a.updatedAt && !b.updatedAt) return a;
    36	    if (!a.updatedAt) return b;
    37	    if (!b.updatedAt) return a;
    38	    return a.updatedAt >= b.updatedAt ? a : b;
    39	}
